mapper.select:
SELECT ID, EQUIP_SMALL_CATEGORY_ID, EQUIP_SMALL_CATEGORY_NAME, EQUIP_ID, EQUIP_NAME, EQUIP_TYPE, INITIAL_DATE, DEADLINE_DATE, SET_DATE, IS_SINGLE, CYCLE, INSPECTOR_ID, INSPECTOR_NAME, STANDARD_ID, CONTENT, STANDARD, TIME_LIMIT, INITIAL_NUMBER, DEADLINE_NUMBER, RECENTLY_TASK_DATE, CREATE_BY, CREATE_BY_NAME, CREATE_TIME FROM E_CHECK_PLAN WHERE 1=1
AND EQUIP_NAME like #{equipName}
AND EQUIP_SMALL_CATEGORY_ID = #{equipSmallCategoryId}
AND EQUIP_TYPE = #{equipType}
order by CREATE_TIME DESC

SELECT ID, EQUIP_PLAN_ID, EQUIP_ID, EQUIP_NAME, START_DATE, END_DATE FROM E_CHECK_TASK WHERE 1=1
AND EQUIP_PLAN_ID = #{equipPlanId}
ORDER BY CREATE_TIME DESC

mapper.insert:
INSERT INTO E_CHECK_PLAN_ITEM( ID, EQUIP_PLAN_ID, STANDARD_ID, EQUIP_SMALL_CATEGORY_ID, EQUIP_SMALL_CATEGORY_NAME, EQUIP_INSTITUTION_ID, EQUIP_INSTITUTION_NAME, EQUIP_UNIT_ID, EQUIP_UNIT_NAME, CONTENT, STANDARD, EQUIP_TYPE, CREATE_BY, CREATE_BY_NAME, CREATE_TIME ) (
select #{item.id}, #{item.equipPlanId}, #{item.standardId}, #{item.equipSmallCategoryId}, #{item.equipSmallCategoryName}, #{item.equipInstitutionId}, #{item.equipInstitutionName}, #{item.equipUnitId}, #{item.equipUnitName}, #{item.content}, #{item.standard}, #{item.equipType}, #{item.loginUserId}, #{item.loginUserName}, #{item.now} from dual
)

INSERT INTO E_CHECK_TASK_ITEM( ID, EQUIP_TASK_ID, STANDARD_ID, EQUIP_PLAN_ID, EQUIP_PLAN_ITEM_ID, EQUIP_SMALL_CATEGORY_ID, EQUIP_SMALL_CATEGORY_NAME, EQUIP_INSTITUTION_ID, EQUIP_INSTITUTION_NAME, EQUIP_UNIT_ID, EQUIP_UNIT_NAME, CONTENT, STANDARD, EQUIP_TYPE, CREATE_BY, CREATE_BY_NAME, CREATE_TIME ) (
select #{item.id}, #{item.equipTaskId}, #{item.standardId}, #{item.equipPlanId}, #{item.equipPlanItemId}, #{item.equipSmallCategoryId}, #{item.equipSmallCategoryName}, #{item.equipInstitutionId}, #{item.equipInstitutionName}, #{item.equipUnitId}, #{item.equipUnitName}, #{item.content}, #{item.standard}, #{item.equipType}, #{item.loginUserId}, #{item.loginUserName}, #{item.now} from dual
)

INSERT INTO E_CHECK_TASK( ID, EQUIP_PLAN_ID, EQUIP_ID, EQUIP_NAME, START_DATE, END_DATE, INITIAL_NUMBER, DEADLINE_NUMBER, INSPECTOR_ID, INSPECTOR_NAME, CREATE_BY, CREATE_BY_NAME, CREATE_TIME ) (
select #{item.id}, #{item.equipPlanId}, #{item.equipId}, #{item.equipName}, #{item.startDate}, #{item.endDate}, #{item.initialNumber}, #{item.deadlineNumber}, #{item.inspectorId}, #{item.inspectorName}, #{item.createBy}, #{item.createByName}, #{item.createTime} from dual
)

mapper.update:
BEGIN

    UPDATE E_CHECK_PLAN
    SET
    DEADLINE_DATE = #{item.deadlineDate},
    DEADLINE_NUMBER = #{item.deadlineNumber},
    RECENTLY_TASK_DATE = #{item.recentlyTaskDate}
    WHERE
    ID = #{item.id};

END;

